module binary_search (
    input wire [2:0] index,
    input wire write_enable,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] obf_memory [7:0]; // 8 entries of 8-bit obf_memory

    initial begin
        obf_memory[0] = 8'h01;
        obf_memory[1] = 8'h02;
        obf_memory[2] = 8'h03;
        obf_memory[3] = 8'h04;
        obf_memory[4] = 8'h05;
        obf_memory[5] = 8'h06;
        obf_memory[6] = 8'h07;
        obf_memory[7] = 8'h08;
    end

    always @(*) begin
        if (write_enable) begin
            obf_memory[index] = data_in; // Write new data to obf_memory
            data_out = 8'bz; // Output is high impedance during write
        end else begin
            data_out = obf_memory[index]; // Read data from obf_memory
        end
    end
endmodule
